import React, { useMemo, useState } from 'react';
import { useParams } from 'react-router-dom';
import './ContentPage.css';

const library = [
  {
    id: 1,
    title: 'Berserk',
    author: 'Kentaro Miura',
    cover: 'https://placehold.co/800x1200/ff6b6b/white?text=Berserk+Cover',
    rating: 4.9,
    chapters: 363,
    views: 1250000,
    description: 'A dark fantasy epic about fate, ambition, and survival.',
    type: 'Manga',
    genres: ['Fantasy', 'Horror', 'Drama', 'Action'],
    status: 'Ongoing',
    year: '1989',
    characters: [
      { name: 'Guts', role: 'Main protagonist' },
      { name: 'Casca', role: 'Lead heroine' },
      { name: 'Griffith', role: 'Antagonist' }
    ]
  },
  {
    id: 2,
    title: 'Solo Leveling',
    author: 'Chugong',
    cover: 'https://placehold.co/800x1200/4ecdc4/white?text=Solo+Leveling',
    rating: 4.8,
    chapters: 179,
    views: 980000,
    description: 'A weak hunter rises to become the strongest.',
    type: 'Manhwa',
    genres: ['Action', 'Fantasy'],
    status: 'Completed',
    year: '2018',
    characters: [
      { name: 'Sung Jin-Woo', role: 'Main protagonist' },
      { name: 'Cha Hae-In', role: 'S-Rank hunter' },
      { name: 'Go Gun-Hee', role: 'Association chairman' }
    ]
  }
];

const defaultReviews = [
  { id: 1, user: 'DarkLord', rating: 5, text: 'Top tier art and atmosphere.' },
  { id: 2, user: 'MangaMaster', rating: 4, text: 'Great pacing and memorable battles.' }
];

const ContentPage = () => {
  const { id } = useParams();
  const [activeTab, setActiveTab] = useState('chapters');
  const [reviews, setReviews] = useState(defaultReviews);
  const [draft, setDraft] = useState({ rating: 5, text: '' });

  const content = useMemo(() => {
    const parsedId = Number(id);
    return library.find((item) => item.id === parsedId) || library[0];
  }, [id]);

  if (!content) {
    return (
      <div className="content-page not-found">
        <h2>Content not found</h2>
        <p>The requested content does not exist.</p>
      </div>
    );
  }

  const handleAddReview = (event) => {
    event.preventDefault();
    const text = draft.text.trim();
    if (!text) return;
    setReviews((prev) => [
      {
        id: Date.now(),
        user: 'You',
        rating: Number(draft.rating),
        text
      },
      ...prev
    ]);
    setDraft({ rating: 5, text: '' });
  };

  return (
    <div className="content-page">
      <div className="content-header">
        <div className="cover-container">
          <img src={content.cover} alt={content.title} className="cover-image" />
        </div>

        <div className="content-info">
          <div className="content-header-row">
            <h1 className="content-title">{content.title}</h1>
            <button className="favorite-btn">
              <i className="far fa-heart"></i>
              Add to favorites
            </button>
          </div>

          <div className="content-meta">
            <span className="meta-item"><i className="fas fa-user"></i>{content.author}</span>
            <span className="meta-item"><i className="fas fa-book"></i>{content.chapters} chapters</span>
            <span className="meta-item"><i className="fas fa-eye"></i>{content.views.toLocaleString()} views</span>
          </div>

          <div className="content-rating">
            <div className="rating-stars">
              {[...Array(5)].map((_, i) => (
                <i key={i} className={`fas fa-star ${i < Math.floor(content.rating) ? 'filled' : ''}`}></i>
              ))}
            </div>
            <span className="rating-value">{content.rating}/5.0</span>
          </div>

          <div className="content-genres">
            {content.genres.map((genre) => (
              <span key={genre} className="genre-tag">{genre}</span>
            ))}
          </div>

          <p className="content-description">{content.description}</p>

          <div className="content-actions">
            <button className="action-btn primary"><i className="fas fa-play"></i>Read from start</button>
            <button className="action-btn secondary"><i className="fas fa-bookmark"></i>Continue reading</button>
            <button className="action-btn secondary"><i className="fas fa-download"></i>Download</button>
          </div>
        </div>
      </div>

      <div className="content-tabs">
        <div className="tabs-nav">
          <button className={`tab-btn ${activeTab === 'chapters' ? 'active' : ''}`} onClick={() => setActiveTab('chapters')}>
            <i className="fas fa-list"></i>Chapters
          </button>
          <button className={`tab-btn ${activeTab === 'characters' ? 'active' : ''}`} onClick={() => setActiveTab('characters')}>
            <i className="fas fa-users"></i>Characters
          </button>
          <button className={`tab-btn ${activeTab === 'reviews' ? 'active' : ''}`} onClick={() => setActiveTab('reviews')}>
            <i className="fas fa-star"></i>Reviews
          </button>
          <button className={`tab-btn ${activeTab === 'info' ? 'active' : ''}`} onClick={() => setActiveTab('info')}>
            <i className="fas fa-info-circle"></i>Info
          </button>
        </div>

        <div className="tab-content">
          {activeTab === 'chapters' && (
            <div className="chapters-list">
              <div className="chapters-header">
                <h3>Chapters</h3>
              </div>
              <div className="chapters-grid">
                {Array.from({ length: 20 }, (_, index) => (
                  <div key={index} className="chapter-card">
                    <div className="chapter-info">
                      <span className="chapter-number">Chapter {content.chapters - index}</span>
                      <span className="chapter-title">Episode title</span>
                      <span className="chapter-date">2 days ago</span>
                    </div>
                    <div className="chapter-actions">
                      <button className="read-btn"><i className="fas fa-book-open"></i>Read</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'characters' && (
            <div className="characters-grid">
              {content.characters.map((char) => (
                <div key={char.name} className="character-card">
                  <div className="character-avatar"><i className="fas fa-user"></i></div>
                  <div className="character-info">
                    <h4>{char.name}</h4>
                    <p>{char.role}</p>
                  </div>
                </div>
              ))}
            </div>
          )}

          {activeTab === 'reviews' && (
            <div className="reviews-section">
              <h3>User reviews</h3>
              <form className="review-form" onSubmit={handleAddReview}>
                <select value={draft.rating} onChange={(e) => setDraft((prev) => ({ ...prev, rating: Number(e.target.value) }))}>
                  {[5, 4, 3, 2, 1].map((r) => (
                    <option key={r} value={r}>{r} stars</option>
                  ))}
                </select>
                <input
                  type="text"
                  value={draft.text}
                  onChange={(e) => setDraft((prev) => ({ ...prev, text: e.target.value }))}
                  placeholder="Write your review..."
                />
                <button type="submit" className="action-btn primary">Post</button>
              </form>
              <div className="reviews-list">
                {reviews.map((review) => (
                  <div key={review.id} className="chapter-card">
                    <strong>{review.user}</strong>
                    <span>{'★'.repeat(review.rating)}</span>
                    <p>{review.text}</p>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'info' && (
            <div className="info-section">
              <div className="info-grid">
                <div className="info-item"><span className="info-label">Type:</span><span className="info-value">{content.type}</span></div>
                <div className="info-item"><span className="info-label">Status:</span><span className="info-value">{content.status}</span></div>
                <div className="info-item"><span className="info-label">Year:</span><span className="info-value">{content.year}</span></div>
                <div className="info-item"><span className="info-label">Genres:</span><span className="info-value">{content.genres.join(', ')}</span></div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ContentPage;
